39	    .leftJoin(deals, eq(deals.showId, shows.id))
40	    .leftJoin(settlements, eq(settlements.showId, shows.id))
41	    .where(lte(shows.date, todayDateString()))
42	    .orderBy(asc(shows.date));
43	}
