45	export async function getShowById(id: string) {
46	  const rows = await db
47	    .select({
48	      show: shows,
49	      artist: artists,
50	      agent: agents,
51	      agency: agencies,
52	      deal: deals,
53	      settlement: settlements,
54	      venue: venues,
55	    })
56	    .from(shows)
57	    .leftJoin(artists, eq(shows.artistId, artists.id))
58	    .leftJoin(agents, eq(artists.agentId, agents.id))
59	    .leftJoin(agencies, eq(agents.agencyId, agencies.id))
60	    .leftJoin(deals, eq(deals.showId, shows.id))
61	    .leftJoin(settlements, eq(settlements.showId, shows.id))
62	    .leftJoin(venues, eq(shows.venueId, venues.id))
63	    .where(eq(shows.id, id));
64	
65	  if (rows.length === 0) return null;
66	  const row = rows[0];
67	
68	  const [showTicketSales, showExpenses, showComps] = await Promise.all([
69	    db
70	      .select()
71	      .from(ticketSales)
72	      .where(eq(ticketSales.showId, id))
73	      .orderBy(desc(ticketSales.capturedAt)),
74	    db
75	      .select()
76	      .from(expenses)
77	      .where(eq(expenses.showId, id))
78	      .orderBy(asc(expenses.enteredAt)),
79	    db.select().from(comps).where(eq(comps.showId, id)),
80	  ]);
81	
82	  let recoups: Recoup[] = [];
83	  if (row.settlement?.recoupsJson) {
84	    try {
85	      const parsed = JSON.parse(row.settlement.recoupsJson);
86	      if (Array.isArray(parsed)) recoups = parsed;
87	    } catch {
