107	  return db
108	    .select({
109	      artist: artists,
110	      agent: agents,
111	      agency: agencies,
112	      showCount: sql<number>`count(${shows.id})`.as("show_count"),
113	      lastShowDate: sql<string | null>`max(${shows.date})`.as("last_show_date"),
114	    })
115	    .from(artists)
116	    .leftJoin(agents, eq(artists.agentId, agents.id))
117	    .leftJoin(agencies, eq(agents.agencyId, agencies.id))
118	    .leftJoin(shows, eq(shows.artistId, artists.id))
119	    .groupBy(artists.id, agents.id, agencies.id)
120	    .orderBy(desc(sql`count(${shows.id})`), asc(artists.name));
121	}
