123	/** Aggregates for the reports page. */
124	export async function getReports() {
125	  const today = todayDateString();
126	
127	  const allShowsRows = await db.select().from(shows);
128	  const pastShowIds = new Set(
129	    allShowsRows.filter((s) => s.date <= today).map((s) => s.id),
130	  );
131	
132	  const allDealsRows = await db.select().from(deals);
133	  const pastDeals = allDealsRows.filter((d) => pastShowIds.has(d.showId));
134	
135	  const allSettlementsRows = await db.select().from(settlements);
136	  const pastSettlements = allSettlementsRows.filter((s) =>
137	    pastShowIds.has(s.showId),
138	  );
139	
140	  const allCompsRows = await db.select().from(comps);
141	  const pastComps = allCompsRows.filter((c) => pastShowIds.has(c.showId));
142	
143	  const dealTypeCounts: Record<string, number> = {};
144	  for (const d of pastDeals) {
145	    dealTypeCounts[d.dealType] = (dealTypeCounts[d.dealType] ?? 0) + 1;
146	  }
147	
148	  const totalDeals = pastDeals.length;
149	  const supportedTypes = ["flat", "percentage_of_gross"];
150	  const supportedCount = pastDeals.filter((d) =>
151	    supportedTypes.includes(d.dealType),
152	  ).length;
153	  const inAppToolUsageRate = totalDeals > 0 ? supportedCount / totalDeals : 0;
154	
155	  const settlementStatus: Record<string, number> = {};
156	  for (const s of pastSettlements) {
157	    settlementStatus[s.status] = (settlementStatus[s.status] ?? 0) + 1;
158	  }
159	
160	  const totalSettlements = pastSettlements.length;
161	  const disputedRate =
162	    totalSettlements > 0
163	      ? (settlementStatus.disputed ?? 0) / totalSettlements
164	      : 0;
165	
166	  const totalGross = pastSettlements.reduce(
167	    (sum, s) => sum + (s.grossBoxOffice ?? 0),
168	    0,
169	  );
170	  const totalToArtists = pastSettlements.reduce(
171	    (sum, s) => sum + (s.totalToArtist ?? 0),
172	    0,
173	  );
174	
175	  const showCount = pastShowIds.size;
176	  const settledCount = pastShowIds.size;
177	
178	  // Bonuses
179	  const dealsWithBonuses = pastDeals.filter((d) => d.bonusesJson).length;
180	
181	  // Recoups
182	  let totalRecoupValue = 0;
183	  let disputedRecoupValue = 0;
184	  let settlementsWithRecoups = 0;
185	  for (const s of pastSettlements) {
186	    if (!s.recoupsJson) continue;
187	    try {
188	      const recoups = JSON.parse(s.recoupsJson) as Recoup[];
189	      if (!Array.isArray(recoups) || recoups.length === 0) continue;
190	      settlementsWithRecoups++;
191	      for (const r of recoups) {
192	        totalRecoupValue += r.amount;
193	        if (r.status === "disputed") disputedRecoupValue += r.amount;
194	      }
195	    } catch {
196	      // skip
197	    }
198	  }
199	
200	  // Comps
201	  const totalCompTickets = pastComps.reduce((s, c) => s + c.count, 0);
202	  const totalCompFaceValue = pastComps.reduce(
203	    (s, c) => s + c.count * c.faceValue,
204	    0,
205	  );
206	  const compsByCategory: Record<string, number> = {};
207	  for (const c of pastComps) {
208	    compsByCategory[c.category] = (compsByCategory[c.category] ?? 0) + c.count;
209	  }
210	
211	  return {
212	    dealTypeCounts,
213	    totalDeals,
214	    inAppToolUsageRate,
215	    settlementStatus,
216	    totalSettlements,
217	    disputedRate,
218	    totalGross,
219	    totalToArtists,
220	    showCount,
221	    settledCount,
222	    dealsWithBonuses,
223	    totalRecoupValue,
224	    disputedRecoupValue,
225	    settlementsWithRecoups,
226	    totalCompTickets,
227	    totalCompFaceValue,
228	    compsByCategory,
229	  };
230	}
231	
232	export type Reports = Awaited<ReturnType<typeof getReports>>;
