1	/**
2	 * Formatting helpers. Money in USD, dates in venue-friendly format.
3	 */
4	
5	import { format, parseISO } from "date-fns";
6	
7	export function formatMoney(amount: number | null | undefined): string {
8	  if (amount == null) return "—";
9	  return new Intl.NumberFormat("en-US", {
10	    style: "currency",
11	    currency: "USD",
12	    maximumFractionDigits: 2,
13	  }).format(amount);
14	}
15	
16	export function formatMoneyCompact(amount: number | null | undefined): string {
17	  if (amount == null) return "—";
18	  if (Math.abs(amount) >= 1000) {
19	    return new Intl.NumberFormat("en-US", {
20	      style: "currency",
21	      currency: "USD",
22	      maximumFractionDigits: 1,
23	      notation: "compact",
24	    }).format(amount);
25	  }
26	  return formatMoney(amount);
27	}
28	
