3	/**
4	 * The Greenroom mark — four vertical bars in a crescendo-peak pattern,
5	 * evoking a live audio level meter frozen at the moment the room peaks.
6	 * Asymmetric: rises medium → tall → tallest → drops to short.
7	 */
8	
9	const BARS = [
10	  { x: 7.5, y: 14.5, h: 11 },
11	  { x: 14.5, y: 11, h: 18 },
