import { cn } from "@/lib/utils";

type Status = "booked" | "advanced" | "day_of" | "settled" | "closed";

const statusStyles: Record<
  Status,
  { bg: string; fg: string; ring: string; dot: string }
> = {
  booked: {
    bg: "bg-ink-100",
    fg: "text-ink-700",
    ring: "ring-ink-200/80",
    dot: "bg-ink-400",
  },
  advanced: {
    bg: "bg-sky-50",
    fg: "text-sky-800",
    ring: "ring-sky-200/80",
    dot: "bg-sky-700",
  },
  day_of: {
    bg: "bg-amber-50",
    fg: "text-amber-800",
    ring: "ring-amber-200/80",
    dot: "bg-amber-700",
  },
  settled: {
    bg: "bg-brand-50",
    fg: "text-brand-800",
    ring: "ring-brand-200/80",
    dot: "bg-brand-700",
  },
  closed: {
    bg: "bg-ink-50",
    fg: "text-ink-500",
    ring: "ring-ink-200/80",
    dot: "bg-ink-400",
  },
};

const statusLabels: Record<Status, string> = {
  booked: "Booked",
  advanced: "Advanced",
  day_of: "Day of",
  settled: "Settled",
  closed: "Closed",
};

export function StatusBadge({
  status,
  className,
  showDot = true,
}: {
  status: Status;
  className?: string;
  showDot?: boolean;
}) {
  const s = statusStyles[status];
  return (
    <span
      className={cn(
        "inline-flex items-center gap-1.5 px-2 py-0.5 rounded-md",
        "text-[10.5px] font-medium ring-1 ring-inset",
        s.bg,
        s.fg,
        s.ring,
        className,
      )}
    >
      {showDot && <span className={cn("w-1.5 h-1.5 rounded-full", s.dot)} />}
      {statusLabels[status]}
    </span>
  );
}

const dealStyles: Record<string, { bg: string; fg: string; ring: string }> = {
  flat: {
    bg: "bg-ink-50",
    fg: "text-ink-700",
    ring: "ring-ink-200/80",
  },
  percentage_of_gross: {
    bg: "bg-ink-50",
    fg: "text-ink-700",
    ring: "ring-ink-200/80",
  },
  percentage_of_net: {
    bg: "bg-amber-50",
    fg: "text-amber-800",
    ring: "ring-amber-200/80",
  },
  vs: {
    bg: "bg-amber-50",
    fg: "text-amber-800",
    ring: "ring-amber-200/80",
  },
  door: {
    bg: "bg-rose-50",
    fg: "text-rose-800",
    ring: "ring-rose-200/80",
  },
};

const dealLabels: Record<string, string> = {
  flat: "Flat",
  percentage_of_gross: "% of gross",
  percentage_of_net: "% of net",
  vs: "Vs deal",
  door: "Door deal",
};

export function DealTypeBadge({
  type,
  className,
}: {
  type: string;
  className?: string;
}) {
  const s = dealStyles[type] ?? dealStyles.flat;
  return (
    <span
      className={cn(
        "inline-flex items-center px-2 py-0.5 rounded-md",
        "text-[10.5px] font-medium ring-1 ring-inset",
        s.bg,
        s.fg,
        s.ring,
        className,
      )}
    >
      {dealLabels[type] ?? type}
    </span>
  );
}

export function PlainBadge({
  children,
  variant = "default",
  className,
}: {
  children: React.ReactNode;
  variant?: "default" | "amber" | "brand" | "rose" | "sky";
  className?: string;
}) {
  const variants = {
    default: "bg-ink-100 text-ink-700 ring-ink-200/80",
    amber: "bg-amber-50 text-amber-800 ring-amber-200/80",
    brand: "bg-brand-50 text-brand-800 ring-brand-200/80",
    rose: "bg-rose-50 text-rose-800 ring-rose-200/80",
    sky: "bg-sky-50 text-sky-800 ring-sky-200/80",
  };
  return (
    <span
      className={cn(
        "inline-flex items-center px-2 py-0.5 rounded-md",
        "text-[10.5px] font-medium ring-1 ring-inset",
        variants[variant],
        className,
      )}
    >
      {children}
    </span>
  );
}

import { cn } from "@/lib/utils";
import { cva, type VariantProps } from "class-variance-authority";
import * as React from "react";

const buttonVariants = cva(
  [
    "inline-flex items-center justify-center gap-1.5",
    "rounded-lg text-[13px] font-medium",
    "transition-all duration-150",
    "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-brand-700 focus-visible:ring-offset-2 focus-visible:ring-offset-canvas",
    "disabled:pointer-events-none disabled:opacity-50",
    "active:translate-y-px",
  ].join(" "),
  {
    variants: {
      variant: {
        brand:
          "bg-brand-700 text-white hover:bg-brand-800 shadow-sm shadow-brand-700/15 ring-1 ring-inset ring-brand-800/20",
        default:
          "bg-ink-900 text-white hover:bg-ink-800 shadow-sm shadow-ink-900/15",
        secondary:
          "bg-white text-ink-900 hover:bg-ink-50 ring-1 ring-inset ring-ink-200/80 shadow-sm",
        outline:
          "border border-ink-300/80 bg-white/80 text-ink-800 hover:bg-white hover:border-ink-400",
        ghost:
          "text-ink-600 hover:bg-ink-100 hover:text-ink-900",
        danger:
          "bg-rose-700 text-white hover:bg-rose-800 shadow-sm",
      },
      size: {
        default: "h-9 px-4",
        sm: "h-7 px-2.5 text-[12px]",
        lg: "h-10 px-5",
        icon: "h-9 w-9 px-0",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  },
);

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, ...props }, ref) => {
    return (
      <button
        ref={ref}
        className={cn(buttonVariants({ variant, size, className }))}
        {...props}
      />
    );
  },
);
Button.displayName = "Button";

